lexer grammar SYsULexer;

// Keywords
Int : 'int';
Void : 'void';
Return : 'return';
If : 'if';
Else : 'else';
While : 'while';
Break : 'break';
Continue : 'continue';
Const : 'const';

// Punctuation
LeftParen : '(';
RightParen : ')';
LeftBracket : '[';
RightBracket : ']';
LeftBrace : '{';
RightBrace : '}';
Semi : ';';
Comma : ',';

// Operators
Plus : '+';
Minus : '-';
Star : '*';
Slash : '/';
Percent : '%';
Ampersand : '&';
Pipe : '|';
Caret : '^';
Less : '<';
Greater : '>';
LessEqual : '<=';
GreaterEqual : '>=';
Equal : '=';
EqualEqual : '==';
ExclaimEqual : '!=';
Exclaim : '!';
LessLess : '<<';
GreaterGreater : '>>';
AmpAmp : '&&';
PipePipe : '||';

// Assignment operators
PlusEqual : '+=';
MinusEqual : '-=';
StarEqual : '*=';
SlashEqual : '/=';
PercentEqual : '%=';
LessLessEqual : '<<=';
GreaterGreaterEqual : '>>=';
AmpEqual : '&=';
PipeEqual : '|=';
CaretEqual : '^=';

Identifier
    :   IdentifierNondigit
        (   IdentifierNondigit
        |   Digit
        )*
    ;

fragment
IdentifierNondigit
    :   Nondigit
    ;

fragment
Nondigit
    :   [a-zA-Z_]
    ;

fragment
Digit
    :   [0-9]
    ;

Constant
    :   IntegerConstant
    |   HexadecimalConstant
    ;

fragment
IntegerConstant
    :   DecimalConstant
    |   OctalConstant
    ;

fragment
DecimalConstant
    :   NonzeroDigit Digit*
    ;

fragment
OctalConstant
    :   '0' OctalDigit*
    ;

fragment
HexadecimalConstant
    :   '0' [xX] HexDigit+
    ;

fragment
NonzeroDigit
    :   [1-9]
    ;

fragment
OctalDigit
    :   [0-7]
    ;

fragment
HexDigit
    :   [0-9a-fA-F]
    ;


// 预处理信息处理，可以从预处理信息中获得文件名以及行号
// 预处理信息中的第一个数字即为行号
LineAfterPreprocessing
    :   '#' Whitespace* ~[\r\n]*
        -> skip
    ;

Whitespace
    :   [ \t]+
        -> skip
    ;

// 换行符号，可以利用这个信息来更新行号
Newline
    :   (   '\r' '\n'?
        |   '\n'
        )
        -> skip
    ;

